function parseNumero(raw, nome = "valor") {
  // Aceita string/number, devolve number finito.
  const n = typeof raw === "number" ? raw : Number(String(raw).trim());
  if (!Number.isFinite(n)) {
    throw new TypeError(`${nome} deve ser número finito (recebido: ${raw})`);
  }
  return n;
}

console.log(parseNumero(" 10 ", "idade")); // 10
// parseNumero("abc") -> TypeError

function exigeString(v, nome = "valor") {
  if (v == null) throw new Error(`${nome} é obrigatório`);
  if (typeof v !== "string") throw new TypeError(`${nome} deve ser string`);
  return v;
}

function stringNaoVazia(v, nome = "valor") {
  const s = exigeString(v, nome).trim();
  if (s === "") throw new Error(`${nome} não pode ser vazio`);
  return s;
}

console.log(stringNaoVazia("  André  ", "nome"));
// stringNaoVazia(" ") -> erro
// stringNaoVazia(null) -> erro

// Identidade (mesma referência)
const a = { id: 1 };
const b = a;
console.log(a === b); // true

// Conteúdo parecido, mas objetos diferentes
const c = { id: 1 };
console.log(a === c); // false

// Equivalência por domínio (id)
function mesmoId(u1, u2) {
  return u1 != null && u2 != null && u1.id === u2.id;
}

console.log(mesmoId(a, c)); // true

function normalizarUser(raw) {
  if (raw == null || typeof raw !== "object") throw new TypeError("user inválido");
  const { id, name } = raw;
  // id pode vir number ou string numérica
  const nid = parseNumero(id, "id");
  const nname = stringNaoVazia(name, "name");
  return { id: nid, name: nname };
}

function normalizarUsers(raw) {
  if (!Array.isArray(raw)) throw new TypeError("users deve ser array");
  return raw.map(normalizarUser);
}

const n = Number("abc");
console.log(n);               // NaN
console.log(n === NaN);       // false
console.log(Number.isNaN(n)); // true

function exigeNumeroFinito(x) {
  if (!Number.isFinite(x)) throw new TypeError("número inválido");
  return x;
}

