export function assert(cond, msg = "assertion failed") {
  if (!cond) throw new Error(msg);
}

export function assertDefined(v, nome = "valor") {
  if (v === undefined) throw new Error(`${nome} não pode ser undefined`);
  return v;
}

export function assertNotNull(v, nome = "valor") {
  if (v === null) throw new Error(`${nome} não pode ser null`);
  return v;
}

export function assertPresent(v, nome = "valor") {
  if (v == null) throw new Error(`${nome} é obrigatório`); // null ou undefined
  return v;
}

export function assertArray(v, nome = "valor") {
  if (!Array.isArray(v)) throw new TypeError(`${nome} deve ser array`);
  return v;
}
